<script lang="ts">
  import { onMount } from 'svelte';
  import { page } from '$app/state';
  import { resolve } from '$app/paths';
  import type { AvCatalogItem, Capture } from '@zztt/aby-domain';

  type TileSize = 'small'|'medium'|'large';
  type Sort = 'title'|'year'|'recent';
  type AudioTrack = {index:number;codec?:string;language?:string;title?:string;channels?:number};
  type SubtitleTrack = {index:number;codec?:string;language?:string;title?:string;forced?:boolean;hearingImpaired?:boolean};
  type SubtitleChoice = {key:string;source:'embedded'|'sidecar'|'opensubtitles';language:string;title:string;forced?:boolean;hearingImpaired?:boolean;stream?:number;sidecar?:number;fileId?:number};
  type VideoProxyState = {state:'missing'|'running'|'ready'|'failed';progress:number;speed?:string;error?:string;objectKey?:string};
  let items = $state<AvCatalogItem[]>([]); let selected = $state<AvCatalogItem|null>(null); let video = $state<HTMLVideoElement|null>(null); let proxyAudio=$state<HTMLAudioElement|null>(null); let videoUrl=$state(''); let proxyAudioUrl=$state('');
  let loading=$state(true); let message=$state(''); let search=$state(''); let kind=$state('all'); let decade=$state('all'); let country=$state('all'); let sort=$state<Sort>('title');
  let settingsOpen=$state(false); let tileSize=$state<TileSize>('medium'); let showTitle=$state(true); let showYear=$state(true); let showDirector=$state(true); let showKind=$state(false); let showCountry=$state(false); let showLanguages=$state(false); let showState=$state(false);
  let speed=$state(1); let audioTracks=$state<AudioTrack[]>([]); let selectedAudio=$state<string|null>(null); let audioProxyStates=$state<Record<number,string>>({}); let subtitleChoices=$state<SubtitleChoice[]>([]); let externalSubtitleLoading=$state(false); let subtitlesOn=$state(true); let doubleSubtitles=$state(false); let primarySubtitle=$state<string|null>(null); let secondarySubtitle=$state<string|null>(null); let subtitleSize=$state(100);
  let captureIn=$state<number|null>(null); let captureOut=$state<number|null>(null); let captureLabel=$state(''); let lastCapture=$state<Capture|null>(null);
  let libraryWidth=$state(44); let priorLibraryWidth=$state(44);
  let videoProxy=$state<VideoProxyState>({state:'missing',progress:0}); let videoDeliveryKind=$state<'original'|'web-proxy'>('original'); let videoProxyTimer:ReturnType<typeof setInterval>|undefined;

  const decades = $derived([...new Set(items.map((item)=>item.year?`${Math.floor(item.year/10)*10}s`:null).filter(Boolean) as string[])].sort());
  const countries = $derived([...new Set(items.flatMap((item)=>item.countries?.length?item.countries:(item.country??'').split(',').map((value)=>value.trim()).filter(Boolean)))].sort());
  const filtered = $derived.by(() => items.filter((item) => {
    const itemCountries=item.countries?.length?item.countries:(item.country??'').split(',').map((value)=>value.trim()).filter(Boolean);
    const haystack=[item.title,item.originalTitle,item.director,item.composer,item.entity,item.saga,...itemCountries,...item.languages,...item.tags].filter(Boolean).join(' ').toLocaleLowerCase();
    if(search.trim()&&!haystack.includes(search.trim().toLocaleLowerCase())) return false;
    if(kind!=='all'&&item.kind!==kind) return false;
    if(decade!=='all'&&(!item.year||`${Math.floor(item.year/10)*10}s`!==decade)) return false;
    if(country!=='all'&&!itemCountries.includes(country)) return false;
    return true;
  }).sort((left,right)=>sort==='year'?(left.year??9999)-(right.year??9999):sort==='recent'?right.createdAt.localeCompare(left.createdAt):left.title.localeCompare(right.title)));

  onMount(async()=>{
    try {
      const response=await fetch('/api/av/items'); const body=await response.json(); if(!response.ok) throw new Error(body.error?.message??'VIEW could not load the AV catalog'); items=body.items??[];
      restoreSettings(); const requested=page.url.searchParams.get('item'); const item=items.find((candidate)=>candidate.id===requested); if(item) await selectItem(item);
    } catch(error){message=error instanceof Error?error.message:'VIEW could not be loaded';} finally{loading=false;}
  });
  onMount(()=>()=>stopVideoProxyPoll());

  function restoreSettings(){const stored=localStorage.getItem('aby.view-gallery-settings');if(!stored)return;try{const value=JSON.parse(stored);tileSize=['small','medium','large'].includes(value.tileSize)?value.tileSize:'medium';showTitle=value.showTitle!==false;showYear=value.showYear!==false;showDirector=value.showDirector!==false;showKind=value.showKind===true;showCountry=value.showCountry===true;showLanguages=value.showLanguages===true;showState=value.showState===true;}catch{/* defaults remain */}}
  function persist(){localStorage.setItem('aby.view-gallery-settings',JSON.stringify({tileSize,showTitle,showYear,showDirector,showKind,showCountry,showLanguages,showState}));}
  function formatTime(ms:number){const seconds=Math.max(0,Math.floor(ms/1000));return `${Math.floor(seconds/60)}:${String(seconds%60).padStart(2,'0')}`;}
  async function selectItem(item:AvCatalogItem){
    stopVideoProxyPoll();selected=item;captureIn=null;captureOut=null;lastCapture=null;audioTracks=[];audioProxyStates={};proxyAudioUrl='';subtitleChoices=[];selectedAudio=null;primarySubtitle=null;secondarySubtitle=null;videoProxy={state:'missing',progress:0};videoDeliveryKind='original';
    const response=await fetch(`/api/av/items/${item.id}/playback`);const body=await response.json();if(!response.ok){message=body.error?.message??'Playback unavailable';return;}if(selected?.id!==item.id)return;
    videoUrl=body.url;videoProxy=body.videoProxy??videoProxy;videoDeliveryKind=body.deliveryKind??'original';audioTracks=body.audioTracks??[];
    const embedded:SubtitleChoice[]=(body.subtitleTracks??[]).map((track:SubtitleTrack)=>({key:`embedded:${track.index}`,source:'embedded',stream:track.index,language:track.language??'und',title:track.title??track.codec??`track ${track.index}`,forced:track.forced,hearingImpaired:track.hearingImpaired}));
    const sidecars:SubtitleChoice[]=(body.sidecarSubtitles??[]).map((track:any,index:number)=>({key:`sidecar:${index}`,source:'sidecar',sidecar:index,language:track.language??'und',title:track.title??track.sourceObjectKey.split('/').at(-1)??`sidecar ${index+1}`,forced:track.forced,hearingImpaired:track.hearingImpaired}));
    subtitleChoices=[...embedded,...sidecars];selectedAudio=audioTracks[0]?`native:${audioTracks[0].index}`:null;primarySubtitle=subtitleChoices.find((choice)=>!choice.forced)?.key??subtitleChoices[0]?.key??null;message=videoDeliveryKind==='web-proxy'?'Using the web MP4 proxy; the archival source is unchanged.':'';void loadExternalSubtitles(item);void loadAudioProxies(item);
    if(videoProxy.state==='running')startVideoProxyPoll(item);
  }
  function closePlayer(){stopVideoProxyPoll();selected=null;videoUrl='';proxyAudioUrl='';captureIn=null;captureOut=null;lastCapture=null;audioTracks=[];subtitleChoices=[];videoProxy={state:'missing',progress:0};}
  function updateSpeed(){if(video)video.playbackRate=speed;if(proxyAudio)proxyAudio.playbackRate=speed;}
  async function updateAudio(){if(!video||selectedAudio===null)return;const [mode,indexText]=selectedAudio.split(':');const stream=Number(indexText);if(mode==='proxy'){video.muted=true;const response=await fetch(`/api/av/items/${selected?.id}/audio-proxies/${stream}/playback`);const body=await response.json();if(!response.ok){message=body.error?.message??'Stereo proxy unavailable';return;}proxyAudioUrl=body.url;message='Using synchronized OGG stereo proxy.';return;}proxyAudioUrl='';video.muted=false;const nativeTracks=(video as HTMLVideoElement&{audioTracks?:ArrayLike<{enabled:boolean}>}).audioTracks;if(!nativeTracks){message='Native track switching is unavailable here. Build the independent OGG stereo proxy.';return;}audioTracks.forEach((track,position)=>{const native=nativeTracks[position];if(native)native.enabled=track.index===stream;});message='';}
  async function loadAudioProxies(item=selected){if(!item)return;const response=await fetch(`/api/av/items/${item.id}/audio-proxies`);const body=await response.json();if(!response.ok||selected?.id!==item.id)return;audioProxyStates=Object.fromEntries((body.proxies??[]).map((proxy:any)=>[proxy.stream,proxy.state]));}
  async function buildAudioProxy(){if(!selected||!selectedAudio)return;const stream=Number(selectedAudio.split(':')[1]);const response=await fetch(`/api/av/items/${selected.id}/audio-proxies/${stream}`,{method:'POST'});const body=await response.json();if(!response.ok){message=body.error?.message??'Audio proxy could not start';return;}audioProxyStates={...audioProxyStates,[stream]:body.proxy.state};message='Building OGG stereo proxy independently from MOVE TO ABY…';const timer=setInterval(async()=>{await loadAudioProxies();if(audioProxyStates[stream]!=='running'){clearInterval(timer);if(audioProxyStates[stream]==='ready'){selectedAudio=`proxy:${stream}`;await updateAudio();}else message='Stereo proxy generation failed.';}},2000);}
  function stopVideoProxyPoll(){if(videoProxyTimer){clearInterval(videoProxyTimer);videoProxyTimer=undefined;}}
  function startVideoProxyPoll(item:AvCatalogItem){stopVideoProxyPoll();videoProxyTimer=setInterval(()=>void loadVideoProxy(item,true),2000);}
  async function loadVideoProxy(item=selected,switchWhenReady=false){if(!item)return;const response=await fetch(`/api/av/items/${item.id}/video-proxy`);const body=await response.json();if(!response.ok||selected?.id!==item.id)return;videoProxy=body.proxy;if(videoProxy.state==='ready'){stopVideoProxyPoll();if(switchWhenReady){const playback=await fetch(`/api/av/items/${item.id}/video-proxy/playback`);const delivery=await playback.json();if(playback.ok&&selected?.id===item.id){videoUrl=delivery.url;videoDeliveryKind='web-proxy';message='MP4 ready and selected. The archival source is unchanged.';}}}else if(videoProxy.state==='failed'){stopVideoProxyPoll();message=videoProxy.error??'MP4 conversion failed.';}}
  async function buildVideoProxy(){if(!selected||videoProxy.state==='running'||videoProxy.state==='ready')return;const item=selected;const response=await fetch(`/api/av/items/${item.id}/video-proxy`,{method:'POST'});const body=await response.json();if(!response.ok){message=body.error?.message??'MP4 conversion could not start';return;}videoProxy=body.proxy;message='Converting to web MP4 with ffmpeg. The archival source remains untouched.';startVideoProxyPoll(item);}
  function sourceVideoFormat(item:AvCatalogItem){const extension=item.sourceObjectKey.split('.').at(-1)?.toLocaleUpperCase()??'VIDEO';return [extension,item.technicalMetadata.videoCodec?.toLocaleUpperCase()].filter(Boolean).join(' · ');}
  function syncProxy(){if(!video||!proxyAudio||!proxyAudioUrl)return;if(Math.abs(proxyAudio.currentTime-video.currentTime)>.25)proxyAudio.currentTime=video.currentTime;proxyAudio.playbackRate=video.playbackRate;if(video.paused)proxyAudio.pause();else void proxyAudio.play();}
  function subtitleLabel(track:SubtitleChoice){return [track.language,track.title,track.source==='sidecar'?'SRT':track.source==='opensubtitles'?'OPEN SUBTITLES':'',track.forced?'forced':'',track.hearingImpaired?'SDH':''].filter(Boolean).join(' · ');}
  function subtitleUrl(choiceKey:string|null){const choice=subtitleChoices.find((candidate)=>candidate.key===choiceKey);if(!selected||!choice)return '';if(choice.source==='embedded')return `/api/av/items/${selected.id}/subtitles/${choice.stream}`;if(choice.source==='sidecar')return `/api/av/items/${selected.id}/sidecar-subtitles/${choice.sidecar}`;return `/api/av/items/${selected.id}/external-subtitles/${choice.fileId}`;}
  async function loadExternalSubtitles(item=selected){if(!item||externalSubtitleLoading)return;externalSubtitleLoading=true;message='Searching configured OpenSubtitles languages…';try{const response=await fetch(`/api/av/items/${item.id}/external-subtitles`);const body=await response.json();if(!response.ok)throw new Error(body.error?.message??'OpenSubtitles search failed');if(selected?.id!==item.id)return;const external:SubtitleChoice[]=(body.candidates??[]).map((candidate:any)=>({key:candidate.key,source:'opensubtitles',fileId:candidate.fileId,language:candidate.language??'und',title:candidate.release??candidate.fileName,hearingImpaired:candidate.hearingImpaired}));subtitleChoices=[...subtitleChoices.filter((choice)=>choice.source!=='opensubtitles'),...external];const current=subtitleChoices.find((choice)=>choice.key===primarySubtitle);if(external.length&&(!current||current.forced))primarySubtitle=external[0].key;message=external.length?`${external.length} OpenSubtitles options · ${(body.settings?.languages??[]).join(' · ')}`:'No OpenSubtitles matches in the configured languages.';}catch(error){message=error instanceof Error?error.message:'OpenSubtitles search failed';}finally{externalSubtitleLoading=false;}}
  function togglePlayerFocus(){if(libraryWidth===0) libraryWidth=priorLibraryWidth; else {priorLibraryWidth=libraryWidth;libraryWidth=0;}}
  function startResize(event:PointerEvent){if(libraryWidth===0)return;const move=(next:PointerEvent)=>libraryWidth=Math.min(68,Math.max(18,next.clientX/window.innerWidth*100));const stop=()=>{window.removeEventListener('pointermove',move);window.removeEventListener('pointerup',stop);};window.addEventListener('pointermove',move);window.addEventListener('pointerup',stop);event.preventDefault();}
  function setCapturePoint(kind:'in'|'out'){const value=Math.round((video?.currentTime??0)*1000);if(kind==='in')captureIn=value;else captureOut=value;}
  async function saveCapture(){if(!selected||captureIn===null||captureOut===null||captureOut<=captureIn){message='Set an IN and an OUT after it.';return;}const response=await fetch('/api/captures',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({mediaKind:'video',avItemId:selected.id,startTimeMs:captureIn,endTimeMs:captureOut,...(captureLabel.trim()?{label:captureLabel.trim()}:{}),annotations:[]})});const body=await response.json();if(!response.ok){message=body.error?.message??'Capture could not be saved';return;}lastCapture=body.capture;message='Capture saved to WORKSPACE.';}
  async function copyCaptureUrl(){if(!lastCapture)return;const url=new URL(resolve('/share/[token]',{token:lastCapture.shareToken}),window.location.origin).href;await navigator.clipboard.writeText(url);message='Closed capture URL copied.';}
</script>

<!-- eslint-disable svelte/no-navigation-without-resolve -->

<svelte:head><title>VIEW · Aby</title><meta name="description" content="Audiovisual mosaic and temporal player." /></svelte:head>

<main class="view" class:playing={Boolean(selected)} class:focus={libraryWidth===0} style={`width:100%;max-width:none;margin:0;padding:0;--library-width:${libraryWidth}vw`}>
  <section class="library">
    <header class="view-toolbar"><div><span>VIEW</span><strong>{filtered.length} / {items.length} FILMS</strong></div><input type="search" bind:value={search} placeholder="SEARCH TITLE · DIRECTOR · COUNTRY · LANGUAGE" aria-label="Search AV catalog" /><select bind:value={kind} aria-label="Kind filter"><option value="all">ALL TYPES</option><option value="film">FILM</option><option value="episode">EPISODE</option><option value="video">VIDEO</option><option value="archive">ARCHIVE</option><option value="personal">PERSONAL</option></select><select bind:value={decade} aria-label="Decade filter"><option value="all">ALL DECADES</option>{#each decades as value (value)}<option value={value}>{value}</option>{/each}</select><select bind:value={country} aria-label="Country filter"><option value="all">ALL COUNTRIES</option>{#each countries as value (value)}<option value={value}>{value}</option>{/each}</select><select bind:value={sort} aria-label="Sort catalog"><option value="title">TITLE</option><option value="year">YEAR</option><option value="recent">RECENT</option></select><button class:active={settingsOpen} onclick={()=>settingsOpen=!settingsOpen} aria-label="Display properties">DISPLAY</button></header>
    {#if settingsOpen}<aside class="display-panel"><header><span>PROPERTIES</span><button onclick={()=>settingsOpen=false}>×</button></header><label><input type="checkbox" bind:checked={showTitle} onchange={persist}/> TITLE</label><label><input type="checkbox" bind:checked={showYear} onchange={persist}/> YEAR</label><label><input type="checkbox" bind:checked={showDirector} onchange={persist}/> DIRECTOR</label><label><input type="checkbox" bind:checked={showKind} onchange={persist}/> TYPE</label><label><input type="checkbox" bind:checked={showCountry} onchange={persist}/> COUNTRY</label><label><input type="checkbox" bind:checked={showLanguages} onchange={persist}/> LANGUAGES</label><label><input type="checkbox" bind:checked={showState} onchange={persist}/> STORAGE STATE</label><h2>SIZE</h2><div>{#each ['small','medium','large'] as size (size)}<button class:active={tileSize===size} onclick={()=>{tileSize=size as TileSize;persist();}}>{size.slice(0,1).toUpperCase()}</button>{/each}</div></aside>{/if}
    {#if loading}<p class="state">…</p>{:else if items.length===0}<div class="empty"><h1>No films committed yet.</h1><p>Source selection and metadata editing now live in INSPECT.</p><a href={resolve('/inspect') + '?media=av'}>OPEN INSPECT · AV</a></div>{:else if filtered.length===0}<p class="state">No films match the current filters.</p>{:else}<div class="mosaic" class:small={tileSize==='small'} class:large={tileSize==='large'}>{#each filtered as item (item.id)}<button class="film" class:active={selected?.id===item.id} onclick={()=>selectItem(item)}><span class="cover">{#if item.posterUrl}<img src={item.posterUrl} alt=""/>{:else}<i>{item.title.slice(0,1)}</i>{/if}<em>{item.kind}</em></span>{#if showTitle||showYear||showDirector||showKind||showCountry||showLanguages||showState}<span class="meta">{#if showTitle}<strong>{item.title}</strong>{/if}{#if showDirector}<small>{item.director??item.treeValue}</small>{/if}{#if showYear}<small>{item.year??'—'}</small>{/if}{#if showKind}<small>{item.kind}</small>{/if}{#if showCountry}<small>{(item.countries?.length?item.countries:[item.country]).filter(Boolean).join(' · ')||'—'}</small>{/if}{#if showLanguages}<small>{item.languages.join(' · ')||'—'}</small>{/if}{#if showState}<small>{item.state}</small>{/if}</span>{/if}</button>{/each}</div>{/if}
  </section>

  {#if selected}<div class="divider" role="separator" aria-orientation="vertical" aria-label="Resize mosaic and player" onpointerdown={startResize}></div><section class="player-panel">
    <header><button onclick={closePlayer}>← MOSAIC</button><div><span>{selected.year??'—'} · {selected.kind} · {selected.state}</span><strong>{selected.title}</strong><small>{selected.director??selected.treeValue}</small></div><button onclick={togglePlayerFocus}>{libraryWidth===0?'SHOW MOSAIC':'PLAYER FOCUS'}</button><a href={resolve('/inspect') + '?media=av'}>INSPECT AV ↗</a></header>
    <div class="player-main">
      <div class="screen" style={`--subtitle-size:${subtitleSize}%`}><!-- svelte-ignore a11y_media_has_caption --><video bind:this={video} src={videoUrl} poster={selected.posterUrl} controls playsinline onloadedmetadata={updateAudio} onplay={syncProxy} onpause={syncProxy} onseeking={syncProxy} onratechange={()=>{speed=video?.playbackRate??1;syncProxy();}}>{#if subtitlesOn&&primarySubtitle!==null}{@const primary=subtitleChoices.find((choice)=>choice.key===primarySubtitle)}{#if primary}<track kind="subtitles" src={subtitleUrl(primarySubtitle)} srclang={primary.language} label={subtitleLabel(primary)} default />{/if}{/if}{#if subtitlesOn&&doubleSubtitles&&secondarySubtitle!==null&&secondarySubtitle!==primarySubtitle}{@const secondary=subtitleChoices.find((choice)=>choice.key===secondarySubtitle)}{#if secondary}<track kind="subtitles" src={subtitleUrl(secondarySubtitle)} srclang={secondary.language} label={subtitleLabel(secondary)} default />{/if}{/if}</video>{#if proxyAudioUrl}<audio bind:this={proxyAudio} src={proxyAudioUrl} oncanplay={syncProxy}></audio>{/if}</div>
      <div class="film-info">{#if selected.originalTitle}<p><span>ORIGINAL</span>{selected.originalTitle}</p>{/if}{#if selected.summary}<p class="summary">{selected.summary}</p>{/if}<dl><div><dt>COUNTRIES</dt><dd>{(selected.countries?.length?selected.countries:[selected.country]).filter(Boolean).join(' · ')||'—'}</dd></div><div><dt>LANGUAGES</dt><dd>{selected.languages.join(' · ')||'—'}</dd></div><div><dt>COMPOSER</dt><dd>{selected.composer??'—'}</dd></div><div><dt>TAGS</dt><dd>{selected.tags.join(' · ')||'—'}</dd></div><div><dt>IMDb</dt><dd>{selected.externalIds.imdb??'—'}</dd></div><div><dt>TMDB</dt><dd>{selected.externalIds.tmdb??'—'}</dd></div></dl>{#if selected.credits.length}<details><summary>CREDITS · {selected.credits.length}</summary><div class="credits">{#each selected.credits as credit (`${credit.role}:${credit.name}:${credit.character??''}`)}<p><strong>{credit.name}</strong><span>{credit.role}{credit.character?` · ${credit.character}`:''}</span></p>{/each}</div></details>{/if}</div>
    </div>
    <aside class="controls">
      <div class="video-convert"><strong>VIDEO</strong><span>{videoDeliveryKind==='web-proxy'?'MP4 · H.264/AAC':sourceVideoFormat(selected)}</span><button class:signal={videoProxy.state==='missing'||videoProxy.state==='failed'} onclick={buildVideoProxy} disabled={videoProxy.state==='running'||videoProxy.state==='ready'}>{videoProxy.state==='ready'?'MP4 READY':videoProxy.state==='running'?`CONVERTING ${Math.round(videoProxy.progress)}%`:'CONVERT MP4'}</button>{#if videoProxy.speed}<small>{videoProxy.speed}</small>{/if}</div>
      <div><strong>AUDIO</strong><select bind:value={selectedAudio} onchange={updateAudio} disabled={!audioTracks.length}>{#if !audioTracks.length}<option value={null}>NO TRACK DATA</option>{/if}{#each audioTracks as track (track.index)}<option value={`native:${track.index}`}>{track.language??'und'} · {track.title??track.codec??`track ${track.index}`}{track.channels?` · ${track.channels}ch`:''} · NATIVE</option>{#if audioProxyStates[track.index]==='ready'}<option value={`proxy:${track.index}`}>{track.language??'und'} · OGG STEREO PROXY</option>{/if}{/each}</select>{#if selectedAudio}<button onclick={buildAudioProxy} disabled={audioProxyStates[Number(selectedAudio.split(':')[1])]==='running'||selectedAudio.startsWith('proxy:')}>{audioProxyStates[Number(selectedAudio.split(':')[1])]==='running'?'BUILDING…':'BUILD STEREO'}</button>{/if}</div>
      <div><strong>SUBTITLES</strong><button class:active={subtitlesOn} onclick={()=>subtitlesOn=!subtitlesOn}>{subtitlesOn?'ON':'OFF'}</button><select bind:value={primarySubtitle} disabled={!subtitleChoices.length}><option value={null}>NO TRACK</option>{#each subtitleChoices as track (track.key)}<option value={track.key}>{subtitleLabel(track)}</option>{/each}</select><button onclick={()=>loadExternalSubtitles()} disabled={externalSubtitleLoading}>{externalSubtitleLoading?'SEARCHING…':'FIND OTHER'}</button></div>
      <div><strong>DOUBLE</strong><button class:active={doubleSubtitles} onclick={()=>doubleSubtitles=!doubleSubtitles}>{doubleSubtitles?'ON':'OFF'}</button><select bind:value={secondarySubtitle} disabled={!doubleSubtitles||!subtitleChoices.length}><option value={null}>NO SECOND TRACK</option>{#each subtitleChoices as track (track.key)}<option value={track.key}>{subtitleLabel(track)}</option>{/each}</select><label>SIZE <input bind:value={subtitleSize} type="range" min="70" max="180"/></label></div>
      <div><strong>SPEED</strong><select bind:value={speed} onchange={updateSpeed}>{#each [.25,.5,.75,1,1.25,1.5,2] as value (value)}<option value={value}>{value}×</option>{/each}</select></div>
      <div class="capture"><strong>CAPTURE</strong><button onclick={()=>setCapturePoint('in')}>IN {captureIn===null?'—':formatTime(captureIn)}</button><button onclick={()=>setCapturePoint('out')}>OUT {captureOut===null?'—':formatTime(captureOut)}</button><input bind:value={captureLabel} placeholder="Annotation / label"/><button class="signal" onclick={saveCapture}>SAVE + SHARE</button>{#if lastCapture}<a href={resolve('/share/[token]',{token:lastCapture.shareToken})} target="_blank">OPEN URL ↗</a><button onclick={copyCaptureUrl}>COPY URL</button>{/if}</div>
    </aside>
  </section>{/if}
  {#if message}<div class="message">{message}</div>{/if}
</main>

<style>
